local redis = require('redis')
local cjson = require("cjson")

local function redisLoad(key)
   local redisHost, redisPort = key:match("^%s*(.-):(.*)%s*$")
    if not (redisHost and redisPort) then
        return nil
    end

    redisHost = string.match(redisHost,"(.-):%d+$")
    if not redisHost or 1 ~= tonumber(redisPort) then
       return nil, "Wrong Redis address, format must be HOST:PORT" 
    end

   local red = redis:new()
   local conn_status, err = red:connect(redisHost, redisPort)

    -- redis:select(dbNum)
    if not (conn_status == 1) then
        return nil, "Cannot connect to Redis server. Error : "..tostring(err) 
    end
 
    return function ()
        -- body
        local val = red:get(key);
        assert(val ~= ngx.null,"Redis value for key:"..key.." is null");
        if val == ngx.null then
            ngx.log(ngx.ERR,'Cannot load plugin. Invalid Redis value.') 
            return nil;
        else
            return (loadstring(val))(); -- Lua 5.1
        end
    end
end

